<script setup lang="ts">
import { computed, ref, onMounted, onBeforeMount } from "vue";
import { filePickerType } from "./type";
import { getFileDomain } from "./lzcApiGatewayProxy";
import type { filePickerPropsType } from "./type";

const emit = defineEmits(["submit", "close"]);

const props = withDefaults(defineProps<filePickerPropsType>(), {
  type: filePickerType.directory,
  boxId: "",
  filterSelectVisible: false,
  multiple: undefined,
  isModal: undefined,
  choiceFileOnly: undefined,
  choiceDirOnly: undefined,
});

const domain = ref('')

// const rootPath=  'https://file.monkeyking.heiyu.space/#/filepicker'
// const targetOrigin ='https://file.monkeyking.heiyu.space'
const rootPath = computed(() => {
  return `${targetOrigin.value}/#/filepicker2`;
});
const targetOrigin = computed(() => {
  return `https://${domain.value}`;
});

const url = computed(() => {
  console.log("props=====>", props);
  // URL query 中的 &, =, # 等字符会导致参数被截断，这里先编码再拼接
  const _props = encodeURIComponent(JSON.stringify(props));
  console.log("JSON.stringify(props)====", _props);
  return rootPath.value + `?props=${_props}`;
});
const ifr = ref();

const interval = ref();

const style = computed(() => {
  if (isMobile()) {
    return {
      width: '100%',
      height: '100%',
      background: 'white'
    }
  }
  return {
    width: '100%',
    height: '100%',
  }
})

window.addEventListener("message", (e) => {
  if (e.data.origin === window.origin) {
    if (e.data.type === "close") {
      emit("close");
    } else if (e.data.type === "submit") {
      emit("submit", e.data.fileList, e.data.source);
    } else if (e.data.type === "init") {
      clearInterval(interval.value);
    }
  }
});

function isMobile() {
  return navigator.userAgent.match(
    /(phone|pad|pod|iPhone|iPod|ios|iPad|Android|Mobile|BlackBerry|IEMobile|MQQBrowser|JUC|Fennec|wOSBrowser|BrowserNG|WebOS|Symbian|Windows Phone)/i,
  )
}

onBeforeMount(async () => {
  const result = await getFileDomain(props.boxId)
  if (result) {
    domain.value = result
  }
});
onMounted(() => {
  interval.value = setInterval(() => {
    ifr.value.contentWindow.postMessage(
      {
        type: "init",
      },
      targetOrigin.value
    );
  }, 500);
});
</script>

<template>
  <iframe
    v-if="domain"
    id="iframe"
    ref="ifr"
    :style="style"
    :src="url"
    frameborder="0"
  ></iframe>
</template>
